class CustomWriter:
    def __init__(self):
        self.sections = {'Section': {'key': 'value'}}
    def write(self, file):
        for section, options in self.sections.items():
            file.write(f'[{section}]\n')
            for key, value in options.items():
                file.write(f'{key} = {value}\n')
config = CustomWriter()
